/**
 * Control Plane Dashboard — Tenant, workspace, connector, and audit management.
 * PLATFORM MANAGEMENT ONLY — no trading execution.
 */
import { useState, useEffect, useCallback } from 'react';
import { api, apiPost } from '../utils/api';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './ControlPlanePage.module.css';

const STATUS_COLORS = { active: '#22C55E', onboarding: '#D29922', suspended: '#EF4444', archived: '#90A3AF' };
const HEALTH_COLORS = { healthy: '#22C55E', degraded: '#D29922', unhealthy: '#EF4444', unknown: '#90A3AF' };

export default function ControlPlanePage() {
  usePageTitle('Control Plane');
  const [overview, setOverview] = useState(null);
  const [tenants, setTenants] = useState([]);
  const [connectors, setConnectors] = useState([]);
  const [audit, setAudit] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showOnboard, setShowOnboard] = useState(false);
  const [onboardType, setOnboardType] = useState('public_saas');
  const [onboardName, setOnboardName] = useState('');

  const fetchAll = useCallback(async () => {
    const [ov, tn, cn, al] = await Promise.all([
      api('/api/control-plane/overview'),
      api('/api/control-plane/tenants'),
      api('/api/control-plane/connectors'),
      api('/api/control-plane/audit-log?limit=20'),
    ]);
    if (ov) setOverview(ov);
    if (tn) setTenants(tn.tenants || []);
    if (cn) setConnectors(cn.connectors || []);
    if (al) setAudit(al.entries || []);
    setLoading(false);
  }, []);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const doOnboard = async () => {
    await apiPost('/api/control-plane/onboard', { tenant_type: onboardType, display_name: onboardName || onboardType });
    setShowOnboard(false); setOnboardName('');
    fetchAll();
  };

  if (loading) return <div className={s.loading}>Loading control plane...</div>;

  const ts = overview?.tenants || {};
  const cs = overview?.connectors || {};

  return (
    <div className={s.page}>
      <div className={s.header}>
        <div>
          <h1 className={s.title}>SaaS Control Plane</h1>
          <p className={s.subtitle}>Tenant isolation, access, and operations — no trading execution</p>
        </div>
        <button onClick={() => setShowOnboard(!showOnboard)} className={s.onboardBtn}>+ Onboard Tenant</button>
      </div>

      {/* Onboard Form */}
      {showOnboard && (
        <GlassPanel className={s.onboardForm}>
          <div className={s.onboardRow}>
            <select value={onboardType} onChange={e => setOnboardType(e.target.value)} className={s.select}>
              {['public_saas', 'selected_cloud', 'internal', 'institutional'].map(t => <option key={t} value={t}>{t}</option>)}
            </select>
            <input type="text" placeholder="Display name..." value={onboardName} onChange={e => setOnboardName(e.target.value)} className={s.input} />
            <button onClick={doOnboard} className={s.createBtn}>Create</button>
          </div>
        </GlassPanel>
      )}

      {/* Stats */}
      <div className={s.statsGrid}>
        <StatCard label="Tenants" value={ts.total || 0} accentColor="#60A5FA" compact />
        {Object.entries(ts.by_type || {}).map(([type, count]) => (
          <StatCard key={type} label={type} value={count} accentColor="#BC8CFF" compact />
        ))}
        <StatCard label="Connectors" value={cs.total || 0} accentColor="#D29922" compact />
        {Object.entries(cs.by_health || {}).map(([h, count]) => (
          <StatCard key={h} label={h} value={count} accentColor={HEALTH_COLORS[h] || '#90A3AF'} compact />
        ))}
      </div>

      <div className={s.mainGrid}>
        {/* Tenants */}
        <GlassPanel>
          <h3 className={s.sectionTitle}>TENANTS ({tenants.length})</h3>
          <table className={s.table}>
            <thead><tr className={s.theadRow}>
              {['Tenant', 'Type', 'Tier', 'Profile', 'Status'].map(h => (
                <th key={h} className={s.th}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {tenants.map(t => (
                <tr key={t.tenant_id} className={s.tr}>
                  <td className={s.tdName}>
                    {t.display_name || t.tenant_id}
                  </td>
                  <td className={s.td}>{t.tenant_type}</td>
                  <td className={s.tdTier}>{t.plan_tier}</td>
                  <td className={s.td}>{t.deployment_profile}</td>
                  <td className={s.td}>
                    <span className={s.statusBadge} style={{ color: STATUS_COLORS[t.status] || '#90A3AF' }}>
                      {(t.status || '').toUpperCase()}
                    </span>
                  </td>
                </tr>
              ))}
              {tenants.length === 0 && <tr><td colSpan={5} className={s.emptyRow}>No tenants</td></tr>}
            </tbody>
          </table>
        </GlassPanel>

        {/* Connectors */}
        <GlassPanel>
          <h3 className={s.sectionTitle}>CONNECTORS</h3>
          {connectors.length === 0 ? (
            <div className={s.emptyBlock}>No connectors</div>
          ) : connectors.map(c => (
            <div key={c.connector_id} className={s.connectorRow}>
              <div>
                <span className={s.connectorType}>{c.connector_type}</span>
                <span className={s.connectorEnv}>{c.environment}</span>
              </div>
              <span className={s.healthBadge} style={{ color: HEALTH_COLORS[c.health] || '#90A3AF' }}>
                {(c.health || 'unknown').toUpperCase()}
              </span>
            </div>
          ))}
        </GlassPanel>
      </div>

      {/* Audit Log */}
      <GlassPanel>
        <h3 className={s.sectionTitle}>AUDIT LOG (Recent)</h3>
        {audit.length === 0 ? (
          <div className={s.emptyBlock}>No audit entries</div>
        ) : (
          <table className={s.tableAudit}>
            <thead><tr className={s.theadRow}>
              {['Time', 'Action', 'Actor', 'Tenant', 'Target'].map(h => (
                <th key={h} className={s.thAudit}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {audit.map((e, i) => (
                <tr key={i} className={s.tr}>
                  <td className={s.tdAudit}>{(e.timestamp || '').slice(11, 19)}</td>
                  <td className={s.tdAction}>{e.action}</td>
                  <td className={s.tdActor}>{e.actor}</td>
                  <td className={s.tdAudit}>{(e.tenant_id || '').slice(0, 15)}</td>
                  <td className={s.tdAudit}>{(e.target || '').slice(0, 15)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </GlassPanel>
    </div>
  );
}
